```bash
nl -ba llvm/lib/Transforms/Vectorize/VPlanAnalysis.h | sed -n '1,220p' && sed -n '220,520p' llvm/lib/Transforms/Vectorize/VPlanAnalysis.h && sed -n '520,900p' llvm/lib/Transforms/Vectorize/VPlanAnalysis.h && git diff || { applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/VPlanAnalysis.h
@@
 class VPTypeAnalysis {
 public:
   VPTypeAnalysis() = default;

   /// Infer the scalar type for a VPValue or VPRecipe.
   Type *inferScalarType(VPValue *V) const {
     if (auto *InstR = dyn_cast<VPWidenRecipe>(V->getDefiningRecipe())) {
       return InstR->getOriginal()->getType();
     }
+    // For replicated instructions, use the underlying IR instruction's result type.
+    if (auto *RepR = dyn_cast<VPReplicateRecipe>(V->getDefiningRecipe())) {
+      if (Instruction *UI = RepR->getUnderlyingInstr())
+        return UI->getType();
+    }
     if (auto *CastR = dyn_cast<VPWidenCastRecipe>(V->getDefiningRecipe())) {
       return CastR->getDestType();
     }
     if (auto *PhiR = dyn_cast<VPHeaderPHIRecipe>(V->getDefiningRecipe())) {
       return PhiR->getIncomingType();
     }
     if (auto *RedPhiR = dyn_cast<VPReductionPHIRecipe>(V->getDefiningRecipe())) {
       return RedPhiR->getIncomingType();
     }
     if (auto *IntToPtrR = dyn_cast<VPIntToPtrRecipe>(V->getDefiningRecipe())) {
       return IntToPtrR->getResultType();
     }
     if (auto *PtrToIntR = dyn_cast<VPPtrToIntRecipe>(V->getDefiningRecipe())) {
       return PtrToIntR->getResultType();
     }
     if (auto *GEP = dyn_cast<VPWidenGEPRecipe>(V->getDefiningRecipe())) {
       return GEP->getResultType();
     }
     if (auto *SelR = dyn_cast<VPWidenSelectRecipe>(V->getDefiningRecipe())) {
       return SelR->getResultType();
     }
     if (auto *LoadR = dyn_cast<VPWidenLoadRecipe>(V->getDefiningRecipe())) {
       return LoadR->getLoadedType();
     }
     if (auto *StoreR = dyn_cast<VPWidenStoreRecipe>(V->getDefiningRecipe())) {
       return StoreR->getValueType();
     }
     // Fall back: for VPValues without a defining recipe or unknown recipe types,
     // try to use the type recorded in the VPValue, if any.
     if (Type *Ty = V->getScalarType())
       return Ty;
     // As a conservative fallback, return nullptr indicating unknown.
     return nullptr;
   }
 };
*** End Patch
EOF
; submit-patch; }
```

