THOUGHT: The assertion calls inferScalarType with a VPReplicateRecipe*, but the public inferScalarType only accepts VPValue*. To ensure correct dispatch, I will add an overload inferScalarType(const VPRecipeBase*) to VPTypeAnalysis and implement it in VPlanAnalysis.cpp to route VPReplicateRecipe to inferScalarTypeForRecipe, which already returns the underlying instruction’s result type for casts. Then I will run the reproducer to validate.

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/VPlanAnalysis.h
@@
   /// Infer the type of \p V. Returns the scalar type of \p V.
   Type *inferScalarType(const VPValue *V);
+  /// Infer the type of \p R. Returns the scalar type produced by \p R.
+  Type *inferScalarType(const VPRecipeBase *R);
*** End Patch
EOF
&& applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/VPlanAnalysis.cpp
@@
 Type *VPTypeAnalysis::inferScalarType(const VPValue *V) {
   if (Type *CachedTy = CachedTypes.lookup(V))
     return CachedTy;
@@
   CachedTypes[V] = ResultTy;
   return ResultTy;
 }
+
+Type *VPTypeAnalysis::inferScalarType(const VPRecipeBase *R) {
+  // Dispatch to the corresponding recipe-specific inference. This ensures calls
+  // like inferScalarType(ReplicateRecipe) return the underlying instruction's
+  // result type for casts and other ops.
+  return TypeSwitch<const VPRecipeBase *, Type *>(R)
+      .Case<VPReplicateRecipe, VPBlendRecipe, VPInstruction, VPWidenRecipe,
+            VPWidenCallRecipe, VPWidenMemoryRecipe, VPWidenSelectRecipe>(
+          [this](const auto *RR) { return inferScalarTypeForRecipe(RR); })
+      .Case<VPWidenCastRecipe, VPInstructionWithType>(
+          [](const auto *RR) { return RR->getResultType(); })
+      .Default([&](const VPRecipeBase *RR) {
+        // Fall back to the operand-based inference if applicable.
+        if (RR->getNumOperands() > 0)
+          return inferScalarType(RR->getOperand(0));
+        // If no operands and no specific handling, this should not happen.
+        llvm_unreachable("Unhandled recipe type for inferScalarType");
+      });
+}
*** End Patch
EOF
&& /llvm-autofix/build/llvm-build/151392/bin/opt -passes=loop-vectorize -force-vector-width=4 -S /tmp/test.ll
```

